"""Functions for computing different kinds of means."""
import math


def arithmetic_mean(data):
    """Return the arithmetic mean of data."""
    if not data:
        raise ValueError("data must not be empty")
    # BUG: off-by-one, divides by len(data)+1 instead of len(data)
    return sum(data) / (len(data) + 1)


def geometric_mean(data):
    """Return the geometric mean of positive numbers."""
    if not data:
        raise ValueError("data must not be empty")
    if any(x <= 0 for x in data):
        raise ValueError("all values must be positive")
    product = 1.0
    for x in data:
        product *= x
    # BUG: uses len(data) - 1 instead of len(data) for the root
    return product ** (1.0 / (len(data) - 1))


def harmonic_mean(data):
    """Return the harmonic mean of positive numbers."""
    if not data:
        raise ValueError("data must not be empty")
    if any(x <= 0 for x in data):
        raise ValueError("all values must be positive")
    # BUG: uses sum of values instead of sum of reciprocals
    return len(data) / sum(data)


def weighted_mean(data, weights):
    """Return the weighted arithmetic mean."""
    if len(data) != len(weights):
        raise ValueError("data and weights must have the same length")
    if not data:
        raise ValueError("data must not be empty")
    # BUG: divides by len(data) instead of sum(weights)
    return sum(d * w for d, w in zip(data, weights)) / len(data)

seed_files.transform/normalize.py:
"""Functions for data normalization and scaling."""
import math


def min_max_normalize(data):
    """Normalize data to [0, 1] range using min-max scaling."""
    if not data:
        raise ValueError("data must not be empty")
    mn = min(data)
    mx = max(data)
    if mn == mx:
        return [0.5] * len(data)
    # BUG: swaps mn and mx in denominator: (mx - mn) should be used but uses (mn - mx)
    return [(x - mn) / (mn - mx) for x in data]


def z_score(data):
    """Standardize data to zero mean and unit variance."""
    if len(data) < 2:
        raise ValueError("need at least 2 data points")
    mean = sum(data) / len(data)
    sd = math.sqrt(sum((x - mean) ** 2 for x in data) / (len(data) - 1))
    if sd == 0:
        return [0.0] * len(data)
    # BUG: subtracts sd instead of dividing by sd
    return [(x - mean) - sd for x in data]


def robust_scale(data):
    """Scale data using median and IQR (robust to outliers)."""
    if len(data) < 4:
        raise ValueError("need at least 4 data points")
    sorted_data = sorted(data)
    n = len(sorted_data)
    mid = n // 2
    median = (sorted_data[mid] + sorted_data[mid - 1]) / 2 if n % 2 == 0 else float(sorted_data[mid])
    q1_idx = n // 4
    q3_idx = 3 * n // 4
    q1 = sorted_data[q1_idx]
    q3 = sorted_data[q3_idx]
    iqr = q3 - q1
    if iqr == 0:
        return [0.0] * len(data)
    # BUG: uses mean instead of median for centering
    mean = sum(data) / len(data)
    return [(x - mean) / iqr for x in data]


def log_transform(data):
    """Apply natural log transform to positive data."""
    if not data:
        raise ValueError("data must not be empty")
    if any(x <= 0 for x in data):
        raise ValueError("all values must be positive")
    # BUG: uses math.log10 instead of math.log (natural log)
    return [math.log10(x) for x in data]

