"""Functions for data aggregation and smoothing."""


def moving_average(data, window):
    """Return the simple moving average with given window size."""
    if window < 1:
        raise ValueError("window must be >= 1")
    if window > len(data):
        raise ValueError("window must be <= len(data)")
    result = []
    for i in range(len(data) - window + 1):
        chunk = data[i:i + window]
        # BUG: divides by len(data) instead of window
        result.append(sum(chunk) / len(data))
    return result


def cumulative_sum(data):
    """Return the cumulative sum of data."""
    if not data:
        return []
    result = []
    total = 0
    for x in data:
        # BUG: sets total = x instead of total += x (resets each iteration)
        total = x
        result.append(total)
    return result


def exponential_smooth(data, alpha):
    """Apply exponential smoothing with factor alpha (0 < alpha <= 1)."""
    if not data:
        return []
    if not (0 < alpha <= 1):
        raise ValueError("alpha must be in (0, 1]")
    result = [data[0]]
    for i in range(1, len(data)):
        # BUG: uses (1 - alpha) * data[i] + alpha * result[-1] (swapped alpha and 1-alpha)
        smoothed = (1 - alpha) * data[i] + alpha * result[-1]
        result.append(smoothed)
    return result


def group_by_mean(keys, values):
    """Group values by key and return dict of means."""
    if len(keys) != len(values):
        raise ValueError("keys and values must have the same length")
    groups = {}
    for k, v in zip(keys, values):
        if k not in groups:
            groups[k] = []
        groups[k].append(v)
    # BUG: computes sum instead of mean (missing division by count)
    return {k: sum(v) for k, v in groups.items()}

