"""Input validation functions."""


def validate_numeric_list(data):
    """Validate that data is a non-empty list of numbers. Returns True or raises."""
    if not isinstance(data, list):
        raise TypeError("data must be a list")
    if len(data) == 0:
        raise ValueError("data must not be empty")
    # BUG: only checks first element instead of all elements
    if not isinstance(data[0], (int, float)):
        raise TypeError("all elements must be numeric")
    return True


def validate_positive(data):
    """Validate that all values in data are positive. Returns True or raises."""
    if not isinstance(data, list):
        raise TypeError("data must be a list")
    for x in data:
        if not isinstance(x, (int, float)):
            raise TypeError(f"expected number, got {type(x).__name__}")
        # BUG: uses < 0 instead of <= 0 (allows zero, but zero is not positive)
        if x < 0:
            raise ValueError(f"all values must be positive, got {x}")
    return True


def validate_non_empty(data):
    """Validate that data is not None and not empty. Returns True or raises ValueError."""
    # BUG: only checks for None, does not check for empty list/string
    if data is None:
        raise ValueError("data must not be empty")
    return True
